#include<bits/stdc++.h>
using namespace std;
int maxans,ans,n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        int x,y;
        cin>>x>>y;
        if(x>=90&&x<=140&&y>=60&&y<=90){
            ans++;
            maxans=max(ans,maxans);
        }else{
            ans=0;
        }
    }
    cout<<maxans;
}
